    \node[below] at (2.5,0.8) {bottom};
    \node[right] at (4,1.9) {right};
    \node[above] at (2.5,2.8) {top};
    \node[left] at (1,1.9) {left};

    \foreach \x in {1.35,2.15,2.95,3.65} {
        \foreach \y in {1.1,1.75,2.35} {
